# ================BUILDING (NEW,SURVEYED,RESURVEYED)========================================================== 	
	LAYER
		NAME 'BLD'
		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo 
		INCLUDE "ReplicaDatashare.inc"	
		DATA 'sp_geometry FROM vw_att_details_building_map USING UNIQUE system_id USING srid=4326'	
		FILTER (%provinceFilter% AND (%layerFilter% ) AND (%bldRFSFilter% ) and (%NetworkFilter%))
		
		VALIDATION		
			'provinceFilter'   '.*'	
            'layerFilter'   '.*'	
			'bldRFSFilter'   '.*'
			'NetworkFilter'   '.*'			
		END 
		METADATA
			'ows_title' 'Building'
		END
		STATUS OFF		
		LABELITEM 'label_column'
		PROJECTION
			'proj=longlat'  
			'datum=WGS84'
			'no_defs'
		END
		CLASS
			NAME 'Building' 	
			EXPRESSION ('[building_status]' eq 'New')			
			STYLE
				SYMBOL [icon_path] 
				SIZE 18			
			END	 
			LEADER
			  GRIDSTEP 6
			  MAXDISTANCE 10000
			  STYLE
				COLOR 200 100 100
				WIDTH 1
			  END
			END
			LABEL
				COLOR  255 0 0  		
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE
			END			
		END
		CLASS
			NAME 'Building' 	
			EXPRESSION ('[building_status]' eq 'Surveyed')			
			STYLE
				SYMBOL [icon_path] 
				SIZE 18			
			END	 
			LEADER
			  GRIDSTEP 6
			  MAXDISTANCE 10000
			  STYLE
				COLOR 200 100 100
				WIDTH 1
			  END
			END
			LABEL
				COLOR  255 0 0  		
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE
			END			
		END
		CLASS
			NAME 'Building' 	
			EXPRESSION ('[building_status]' eq 'Resurveyed')			
			STYLE
				SYMBOL [icon_path]
				SIZE 18			
			END	 
			LEADER
			  GRIDSTEP 6
			  MAXDISTANCE 10000
			  STYLE
				COLOR 200 100 100
				WIDTH 1
			  END
			END
			LABEL
				COLOR  255 0 0  		
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE
			END			
		END		
		
	END
	
