# ==================================SPLICE CLOSURE========================================
LAYER
		NAME 'SC'
		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo 
		INCLUDE "ReplicaDatashare.inc"	
		DATA 'sp_geometry FROM vw_att_details_spliceclosure_map USING UNIQUE system_id USING srid=4326'	
		FILTER (%provinceFilter% AND (%layerFilter% ) AND (%prjectspecificationFilter% ) AND (%ownershipFilter% ) AND (%PODFilter% ) and (%NetworkFilter%)AND (%AutoPlanningNetworkFilter%))
		
		VALIDATION		
			'provinceFilter'   '.*'
			'layerFilter'   '.*'
			'prjectspecificationFilter'   '.*'
			'ownershipFilter'   '.*'	
			'PODFilter'   '.*'
            'NetworkFilter' '.*'			
			'AutoPlanningNetworkFilter' '.*'
		END 
		METADATA
			'ows_title' 'SPLICECLOSURE'
		END
		STATUS OFF
		LABELITEM 'label_column'
		GROUP 'Network'	
		CLASS
			NAME 'MANHOLE'
            EXPRESSION ('[is_buried]' eq '1' and '[network_status]'  eq 'P')  			
			STYLE
				SYMBOL "icons/Planned/v_spliceclosure.png" 
				SIZE 30
				OFFSET 0 -5				
			END
			LEADER
			  GRIDSTEP 6
			  MAXDISTANCE 10000
			  STYLE
				COLOR 200 100 100
				WIDTH 1
			  END
			END
            LABEL 
				COLOR  255 0 0  		
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO  				
                PARTIALS FALSE							
			END	
            			
		END
