			'ows_title' 'ROW'
		END
		STATUS OFF
		GROUP 'Network'
		TRANSPARENCY 30
		PROJECTION
			'proj=longlat'  
			'datum=WGS84'
			'no_defs'
		END			
		
		CLASS
			NAME 'ROW' 
			TEXT "[row_text]"	
			STYLE
				WIDTH 1
				OUTLINECOLOR 0 0 0
				COLOR 125 249 255
			END
			LABEL
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0				
				SIZE 8								
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE				
			END		
		END
	END
	
